SELECT count(*) FROM aka_name, name, cast_info, role_type, char_name, title, movie_companies, company_name, company_type WHERE aka_name.person_id = name.id AND cast_info.person_id = name.id AND cast_info.role_id = role_type.id AND cast_info.person_role_id = char_name.id AND cast_info.movie_id = title.id AND movie_companies.movie_id = title.id AND movie_companies.company_id = company_name.id AND movie_companies.company_type_id = company_type.id;